create table dirkspzm32.aps_modellparameter (
    name                    varchar2(50 char) default 'Standard',
    personalplanen          number(*, 0) default 1,
    fhmplanen               number(*, 0) default 0,
    mehrmaschinenbedienung  number(*, 0) default 1,
    mindauermehrschicht     number(*, 0) default 300,
    mindauerbedienintervall number(*, 0) default 120,
    mindauermmb             number(*, 0) default 2,
    maxbedienanteil         number(*, 0) default 100,
    maxruestanteil          number(*, 0) default 100,
    minbedienanteil         number(*, 0) default 0,
    aufschlagmmb            number(*, 0) default 0,
    kritisch                number(*, 0) default 4320,
    verspaetet              number(*, 0) default 0,
    kapbindzins             number(*, 0) default 3,
    zielfunktionstyp        number(*, 0) default 1,
    dzrende                 date,
    pzrstart                date,
    pzrende                 date,
    istlinie                date,
    istliniesystemzeit      number(*, 0) default 1,
    pzrdzrautomberechnen    number(*, 0) default 1,
    kapazitaetvoristlinie   number(*, 0) default 7200,
    kapazitaetabistlinie    number(*, 0) default 216000,
    datenabistlinie         number(*, 0) default 288000,
    sicherheitszeit         number(*, 0) default 2880,
    puffermatlief           number(*, 0) default 2880,
    ruestueberlappen        number(*, 0) default 0,
    liegenueberlappen       number(*, 0) default 0,
    autobdefa               number(*, 0) default 0,
    autobdesekfa            number(*, 0) default 0,
    priolagerbedarf         number(*, 0)
);


